import { useEffect, useState } from "react";
import { Flag, Star, Trophy, ChevronRight, Clock } from "lucide-react";

interface DemoProps {
  topImage: string;
  activityTitle: string;
  startButtonText: string;
  showCountdown: boolean;
  countdownEndDate: string;
  totalLevels: number;
  themeColor: string;
}

interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

function calcTimeLeft(endDate: string): TimeLeft {
  const diff = new Date(endDate).getTime() - Date.now();
  if (diff <= 0) return { days: 0, hours: 0, minutes: 0, seconds: 0 };
  return {
    days: Math.floor(diff / (1000 * 60 * 60 * 24)),
    hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
    minutes: Math.floor((diff / (1000 * 60)) % 60),
    seconds: Math.floor((diff / 1000) % 60),
  };
}

export default function Demo({
  topImage,
  activityTitle,
  startButtonText,
  showCountdown,
  countdownEndDate,
  totalLevels,
  themeColor,
}: DemoProps) {
  const [timeLeft, setTimeLeft] = useState<TimeLeft>(() =>
    calcTimeLeft(countdownEndDate)
  );

  useEffect(() => {
    if (!showCountdown) return;
    const timer = setInterval(() => {
      setTimeLeft(calcTimeLeft(countdownEndDate));
    }, 1000);
    return () => clearInterval(timer);
  }, [showCountdown, countdownEndDate]);

  const countdownItems = [
    { label: "天", value: timeLeft.days },
    { label: "时", value: timeLeft.hours },
    { label: "分", value: timeLeft.minutes },
    { label: "秒", value: timeLeft.seconds },
  ];

  const levelIcons = [
    <Flag key="flag" className="w-6 h-6" />,
    <Star key="star" className="w-6 h-6" />,
    <Trophy key="trophy" className="w-6 h-6" />,
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Banner */}
      <div
        className="relative w-full pt-12 pb-20 px-6 overflow-hidden"
        style={{
          background: topImage
            ? `url(${topImage}) center/cover no-repeat`
            : `linear-gradient(135deg, ${themeColor}, ${themeColor}dd, #1a1a2e)`,
        }}
      >
        {topImage && (
          <div
            className="absolute inset-0"
            style={{
              background: `linear-gradient(180deg, ${themeColor}44 0%, ${themeColor}cc 100%)`,
            }}
          />
        )}
        <div className="relative z-10 text-center">
          <h1 className="text-3xl font-bold text-white mb-2 drop-shadow-lg">
            {activityTitle}
          </h1>
          <p className="text-white/80 text-sm">挑战自我，赢取大奖</p>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 px-4 -mt-12 space-y-4 pb-24">
        {/* Countdown */}
        {showCountdown && (
          <div className="bg-white rounded-2xl shadow-lg p-5">
            <div className="flex items-center gap-2 mb-3">
              <Clock className="w-5 h-5" style={{ color: themeColor }} />
              <span className="font-semibold text-gray-800">活动倒计时</span>
            </div>
            <div className="flex justify-center gap-3">
              {countdownItems.map((item) => (
                <div key={item.label} className="flex flex-col items-center">
                  <div
                    className="w-16 h-16 rounded-xl flex items-center justify-center text-2xl font-bold text-white shadow-md"
                    style={{ backgroundColor: themeColor }}
                  >
