    requiredLevel: number;
    rarity: 'common' | 'rare' | 'epic' | 'legendary';
    stock: number;
  }[];
  themeColor: string;
  headerImage: string;
  showStock: boolean;
}

import { Gift, Lock, Shield, Sparkles, ArrowLeft, Package } from 'lucide-react';

const RARITY_CONFIG: Record<string, { label: string; bg: string; text: string; border: string }> = {
  common: { label: '普通', bg: 'bg-gray-50', text: 'text-gray-500', border: 'border-gray-200' },
  rare: { label: '稀有', bg: 'bg-blue-50', text: 'text-blue-600', border: 'border-blue-200' },
  epic: { label: '史诗', bg: 'bg-purple-50', text: 'text-purple-600', border: 'border-purple-200' },
  legendary: { label: '传说', bg: 'bg-amber-50', text: 'text-amber-600', border: 'border-amber-200' },
};

export default function Demo({
  title = '全部奖品',
  subtitle = '闯关越多，奖品越丰厚',
  prizes = [],
  themeColor = '#8B5CF6',
  headerImage = '',
  showStock = true,
}: DemoProps) {
  // Sort prizes: by requiredLevel ascending, then by rarity weight
  const sortedPrizes = [...prizes].sort((a, b) => {
    if (a.requiredLevel !== b.requiredLevel) return a.requiredLevel - b.requiredLevel;
    const rarityOrder = { legendary: 0, epic: 1, rare: 2, common: 3 };
    return (rarityOrder[a.rarity] ?? 99) - (rarityOrder[b.rarity] ?? 99);
  });

  // Group by level
  const levelGroups: Record<number, typeof prizes> = {};
  sortedPrizes.forEach(p => {
    if (!levelGroups[p.requiredLevel]) levelGroups[p.requiredLevel] = [];
    levelGroups[p.requiredLevel].push(p);
  });

  const levelKeys = Object.keys(levelGroups).map(Number).sort((a, b) => a - b);

  return (
    <div className="min-h-screen bg-gradient-to-b from-gray-50 to-gray-100">
      {/* Header */}
      <div
        className="relative pt-10 pb-8 px-4 text-center overflow-hidden"
        style={{
          background: headerImage
            ? `url(${headerImage}) center/cover no-repeat`
            : `linear-gradient(135deg, ${themeColor}, #7C3AED 80%, #6D28D9)`,
        }}
      >
        {headerImage && <div className="absolute inset-0 bg-black/30" />}

        {/* Decorative elements */}
        {!headerImage && (
          <>
            <div className="absolute -top-6 -right-6 w-28 h-28 rounded-full bg-white/10" />
            <div className="absolute -bottom-4 -left-4 w-20 h-20 rounded-full bg-white/8" />
